if (!function_exists('prod_t')) {
  function prod_t($key, $fallback = '') { return lang_text($key, $fallback); }
}
if (!function_exists('prod_h')) {
  function prod_h($key, $fallback = '') { return htmlspecialchars((string) prod_t($key, $fallback), ENT_QUOTES, 'UTF-8'); }
}
if (!function_exists('prod_js')) {
  function prod_js($key, $fallback = '') { return json_encode(prod_t($key, $fallback), JSON_HEX_TAG | JSON_HEX_APOS | JSON_HEX_AMP | JSON_HEX_QUOT); }
}
$defaultFrom=date('Y-m-d',strtotime('-30 days'));$defaultTo=date('Y-m-d');
$plants=$db->query("SELECT DISTINCT plant FROM production_order WHERE plant IS NOT NULL AND plant<>'' ORDER BY plant");
$kpi=$db->fetch("SELECT COALESCE(SUM(conf.yield_qty),0) yield_qty,COALESCE(SUM(conf.scrap_qty),0) scrap_qty,COALESCE(SUM(conf.rework_qty),0) rework_qty,COALESCE(SUM(gr.gr_qty),0) gr_qty FROM production_order p LEFT JOIN(SELECT id_production_order,SUM(CASE WHEN status='POSTED' THEN yield_qty ELSE 0 END) yield_qty,SUM(CASE WHEN status='POSTED' THEN scrap_qty ELSE 0 END) scrap_qty,SUM(CASE WHEN status='POSTED' THEN rework_qty ELSE 0 END) rework_qty FROM production_order_confirmation GROUP BY id_production_order) conf ON conf.id_production_order=p.id_production_order LEFT JOIN(SELECT h.id_production_order,SUM(CASE WHEN h.status='POSTED' THEN d.qty ELSE 0 END) gr_qty FROM erp_gr_production h JOIN erp_gr_production_detail d ON d.gr_id=h.id GROUP BY h.id_production_order) gr ON gr.id_production_order=p.id_production_order WHERE p.status IN ('RELEASED','IN_PROCESS','CONFIRMED','TECO','CLOSED') AND p.start_date BETWEEN ? AND ?",array($defaultFrom,$defaultTo));
$outstanding=(float)$kpi->yield_qty-(float)$kpi->gr_qty;
?>
