<script>
function omError(m){$('.isi_warning_delete').text(m||<?=prod_js('production_output_monitoring_process_failed', 'Output Monitoring failed to process.');?>);$('.error_data_delete').fadeIn();}
function omFilters(){return{tgl_awal:$('#filter_tgl_awal').val(),tgl_akhir:$('#filter_tgl_akhir').val(),plant:$('#filter_plant').val(),po_status:$('#filter_po_status').val(),output_status:$('#filter_output_status').val(),keyword:$('#filter_keyword').val()};}
function omQuery(){return $.param(omFilters());}
$(function(){if($.fn.datepicker){$('.om-date').datepicker({format:'yyyy-mm-dd',autoclose:true,todayHighlight:true});}if($.fn.select2){$('#filter_plant,#filter_po_status,#filter_output_status').select2({width:'100%',allowClear:true});}
var dt=$('#dtb_output_monitoring').DataTable({bProcessing:true,bServerSide:true,pageLength:25,ordering:false,dom:"<'row'<'col-sm-12'B>>"+"<'row'<'col-sm-6'l><'col-sm-6'f>>"+"<'row'<'col-sm-12'tr>>"+"<'row'<'col-sm-5'i><'col-sm-7'p>>",buttons:[{extend:'collection',text:<?=prod_js('common_export_data', 'Export Data');?>,buttons:['copyHtml5','excelHtml5','csvHtml5','pdfHtml5']}],columnDefs:[{targets:[0,1],orderable:false,searchable:false},{width:'38px',targets:0},{width:'100px',targets:1},{className:'om-progress',targets:[6,7]}],ajax:{url:'<?=base_admin();?>modul/output_monitoring/output_monitoring_data.php',type:'post',data:function(d){$.extend(d,omFilters());},error:function(xhr){console.log(xhr.responseText);omError(<?=prod_js('production_output_monitoring_load_failed', 'Output Monitoring data failed to load.');?>);}}});
$('#btn_filter_om').click(function(){dt.draw();});$('#filter_keyword').keyup(function(e){if(e.keyCode===13)dt.draw();});$('#btn_reset_om').click(function(){$('#filter_tgl_awal').val('<?=$defaultFrom;?>');$('#filter_tgl_akhir').val('<?=$defaultTo;?>');$('#filter_plant,#filter_po_status,#filter_output_status').val('').trigger('change');$('#filter_keyword').val('');dt.draw();});$('#btn_excel_om').click(function(){window.location='<?=base_admin();?>modul/output_monitoring/output_monitoring_action.php?act=excel&'+omQuery();});
$(document).on('click','.btn-om-detail',function(){$.post('<?=base_admin();?>modul/output_monitoring/output_monitoring_action.php?act=detail',{id:$(this).data('id')},function(html){$('#om_detail_body').html(html);$('#modal_detail_om').modal('show');}).fail(function(){omError(<?=prod_js('production_detail_open_failed', 'Detail failed to open.');?>);});});$('.hide_alert_notif').click(function(){$('.error_data_delete').hide();});
});
